import{_ as u,o as b,c as f,a6 as K,gn as k,go as x,gp as P,gq as C,gr as S,es as V,gs as D,gt as E,gu as L,gv as v,gw as A,gh as F,gx as T,gy as p,gz as w,gA as I,gB as N,gC as B,gD as O,gE as G,gF as g,gG as s,gH as n,gI as $,gJ as i,gK as y,gL as l,gM as H,gN as M,gO as Q,gP as R,gQ as j,gR as q,gS as e,gT as m,gU as U,gV as J,gW as X,gX as z,gY as W,gZ as Y,ey as Z,g_ as pp,g$ as sp,h0 as tp,h1 as rp,h2 as ap,h3 as op,h4 as gp,h5 as np,h6 as ip,h7 as lp,h8 as ep,h9 as mp,ha as h,hb as t,hc as _,hd as c,he as hp,hf as _p,hg as cp,hh as dp,hi as up,hj as bp,hk as fp,hl as Kp,hm as kp,hn as xp,ho as Pp,hp as Cp,hq as Sp,hr as Vp,hs as Dp,ht as Ep,hu as Lp,hv as vp,hw as Ap,hx as Fp,eu as Tp,hy as wp,hz as Ip,hA as Np,hB as Bp,hC as Op,hD as Gp,hE as $p,hF as yp,hG as Hp,hH as Mp,hI as Qp,hJ as Rp,hK as jp,hL as r,hM as qp,hN as Up,hO as d,hP as a,hQ as Jp,hR as Xp,hS as zp,hT as Wp,hU as Yp}from"./chunks/framework.UYVGz2W_.js";const ns=JSON.parse('{"title":"長編映画制作の作成","description":"","frontmatter":{},"headers":[],"relativePath":"ja/feature/index.md","filePath":"ja/feature/index.md"}'),Zp={name:"ja/feature/index.md"};function ps(ss,o,ts,rs,as,os){return b(),f("div",null,[...o[0]||(o[0]=[K('<h1 id="長編映画制作の作成" tabindex="-1">長編映画制作の作成 <a class="header-anchor" href="#長編映画制作の作成" aria-label="Permalink to “長編映画制作の作成”">​</a></h1><p>Kitsuでワークフローを設計し、より多くの人を招待したので、今度は制作を作成します。</p><p>[新しい制作を作成]ボタンをクリック します。</p><p><img src="'+k+'" alt="制作を作成"></p><p>作品名を入力し、<strong>タイプ</strong>として<strong>長編映画</strong>を選択し、作品のスタイル（2D、3D）を選択します。</p><p>次に、FPS数、アスペクト比、解像度などの技術情報を入力します。</p><p>これらのデータは、Kitsuがアップロードされたビデオプレビューを再エンコードする際に使用されます。</p><p>次に、作品の開始日と終了日を定義する必要があります。</p><p><img src="'+x+'" alt="プロダクションの追加"></p><p>プロダクションのワークフローは、次のパート3から6で定義できます。</p><p>アセットタスクタイプ（3）、ショットタスクタイプ（4）、タスクステータス（5）、アセットタイプ（6）を選択する必要があります。</p><p><img src="'+P+'" alt="Add a production Pipeline"></p><p>::: ヒント <strong>制作ワークフロー</strong>を作成するには、グローバルライブラリからタスクタイプを選択します。</p><p>タスクタイプをいくつか見落としていたことに気づいた場合は、後で作成することができます。</p><p><a href="./../configure-kitsu/#studio-workflow">スタジオワークフロー</a> のセクションを参照してください。 :::</p><p>次に、7と8はオプション部分です。アセット/ショットの一覧が記載されたスプレッドシートがすでに用意されている場合は、</p><p><strong>インポートCSV</strong>のセクションを参照してください。</p><p>アセットのインポート</p><p>ショットのインポート</p><p><img src="'+C+'" alt="All done"> ボタンですべてを検証します。</p><h2 id="kitsuグローバルページの紹介" tabindex="-1">Kitsuグローバルページの紹介 <a class="header-anchor" href="#kitsuグローバルページの紹介" aria-label="Permalink to “Kitsuグローバルページの紹介”">​</a></h2><p>Kitsuのグローバルアセットページへようこそ。</p><p>見てみましょう。</p><p><img src="'+S+'" alt="グローバルページの紹介"></p><p>上部 (1) には、<strong>グローバルナビゲーション</strong> があり、これはすべての制作ページで常に表示されます。</p><p><strong>左から右へ:</strong></p><h3 id="メインメニュー" tabindex="-1">メインメニュー <a class="header-anchor" href="#メインメニュー" aria-label="Permalink to “メインメニュー”">​</a></h3><p>左上のボタン、Kitsu<img src="'+V+'" alt="メインメニューボタン">（またはお客様のスタジオロゴ）をクリックすると、メインメニューが開きます。</p><p>メインメニューでは、割り当てられたタスク、制作物、グローバルおよびチームスケジュール、ワークフローのカスタマイズページ、およびKitsu設定に直接アクセスできます。</p><p>::: 詳細 メインメニューの詳細 <strong>ワークスペース</strong></p><ul><li>マイタスク：割り当てられたタスク</li><li>マイチェック：あなたの部署に応じて、ステータスが<strong>フィードバックリクエスト</strong>となっているすべてのタスク</li><li>マイプロダクション：プロダクションページの選択に戻ります。</li></ul><p><strong>スタジオ</strong></p><ul><li>プロダクション</li><li>担当者</li><li>タイムシート</li><li>メインスケジュール</li><li>チームスケジュール</li><li>すべてのタスク</li><li>ニュースフィード</li><li>エンティティ検索</li></ul><p><strong>ADMIN</strong></p><ul><li>部署</li><li>タスクの種類</li><li>アセットの種類</li><li>カスタムアクション</li><li>自動化</li><li>3D背景</li><li>ボット</li><li>設定</li><li>ログ</li></ul><p>::: 警告 権限の表示 ワークスペースセクションは、アーティストには表示されない「マイチェック」を除くすべての権限に対して有効になっています。</p><p>アーティスト（およびそれ以上）は、自身の<strong>タイムシート</strong>も表示でき、<strong>エンティティ検索</strong>にもアクセスできます :::</p><h3 id="ナビゲーション" tabindex="-1">ナビゲーション <a class="header-anchor" href="#ナビゲーション" aria-label="Permalink to “ナビゲーション”">​</a></h3><p>メインメニューアイコンの右側にナビゲーションドロップダウンメニューが表示されます。</p><p><img src="'+D+'" alt="グローバルページの表示"></p><p>制作を選択できます。実際の制作名と実際のページ名が常に表示されます。</p><p>ドロップダウンメニューを使用して、制作から制作へと移動できます（複数の制作がある場合）。</p><p>制作を選択すると、次のドロップダウンメニューで、その制作の異なるページを移動することができます。</p><p>::: 詳細 ナビゲーション詳細 最初のセクションは、タスクのトラッキングについてです。</p><ul><li>アセット</li><li>ショット</li><li>シーケンス</li><li>編集（特定のタスクを作成した場合）</li></ul><p>2番目のセクションは、制作の側面についてです。</p><ul><li>コンセプト</li><li>ブレイクダウン</li><li>プレイリスト</li><li>ニュースフィード</li></ul><p>3番目のセクションは統計情報です</p><ul><li>シーケンス統計</li><li>アセットタイプ統計</li></ul><p>4番目のセクションはチーム管理に関連しています</p><ul><li>スケジュール</li><li>クォータ</li><li>チーム</li></ul><p>5番目のセクションは制作の設定です</p><ul><li>設定</li></ul><p>::: ヒント アセットページから開始しますが、制作ホームページを他のエンティティに変更することができます（設定ページを参照）。 :::</p><h3 id="グローバル検索、ニュース、通知、およびドキュメント" tabindex="-1">グローバル検索、ニュース、通知、およびドキュメント <a class="header-anchor" href="#グローバル検索、ニュース、通知、およびドキュメント" aria-label="Permalink to “グローバル検索、ニュース、通知、およびドキュメント”">​</a></h3><p>グローバル検索はナビゲーションドロップダウンメニューの右側にあります。 4つの最初の結果を表示するクイックアクセス検索です。 さらに多くの結果やフィルタリングオプションが必要な場合は、<strong>エンティティ検索</strong>ページを参照してください。</p><p>次のアイコン <img src="'+E+'" alt="ニュース"> は、ニュースとフィードバックページへの直接リンクです。</p><p>アニメーションGIFで新機能のすべてをご覧いただけます。また、Kitsuに追加してほしい次期機能に関するご意見もご投稿いただけます。</p><p>ベルのアイコンは、通知（割り当て、コメント、タグ）を表示します！<a href="../img/getting-started/notification_icon_on.png">通知</a>。未読の通知の数は、ベルのアイコンに表示されます。</p><p>アバターの直前のアイコンは、ドキュメントボタンです。 <img src="'+L+'" alt="ドキュメントボタン"> あなたが今読んでいるドキュメントです！</p><h3 id="個人設定" tabindex="-1">個人設定 <a class="header-anchor" href="#個人設定" aria-label="Permalink to “個人設定”">​</a></h3><p>アバターをクリックすると、メニュー（設定、ドキュメントなど）を開くことができます。</p><p><img src="'+v+'" alt="プロフィール拡大"></p><h2 id="タスクリスト" tabindex="-1">タスクリスト <a class="header-anchor" href="#タスクリスト" aria-label="Permalink to “タスクリスト”">​</a></h2><h3 id="エンティティスプレッドシート" tabindex="-1">エンティティスプレッドシート <a class="header-anchor" href="#エンティティスプレッドシート" aria-label="Permalink to “エンティティスプレッドシート”">​</a></h3><p>画面の2番目の部分は、すべてのエンティティ（アセット、ショット、シーケンス、編集）に共通です。これはグローバルなタスクスプレッドシートです。</p><p>ここでは、各タスクのステータス、割り当て、優先度などを確認できます。</p><p>::: ヒント スプレッドシートの最初の行と列のヘッダーは、ページを下にスクロールしても常にページの上部に表示されます。</p><p>また、他の列を常に表示しておくために「固定」することもできます。 :::</p><h3 id="フィルター" tabindex="-1">フィルター <a class="header-anchor" href="#フィルター" aria-label="Permalink to “フィルター”">​</a></h3><p>左側の最初の要素はフィルターボックスです。 簡単なフィルタリング、シーケンス、アセットタイプなど、お好きなものを入力できます。</p><p>より高度なフィルタリングが必要な場合は、フィルタービルダーボタンを使用してください。</p><p><img src="'+A+'" alt="フィルタービルダー"></p><p>すべてのフィルターを保存し、ページとして使用することができます。</p><p>::: 警告 長編映画のフィルターを起動するには、キーボードの「<strong>Enter</strong>」キーを押す必要があります。 :::</p><h3 id="表示の簡素化" tabindex="-1">表示の簡素化 <a class="header-anchor" href="#表示の簡素化" aria-label="Permalink to “表示の簡素化”">​</a></h3><p>画面の右側には、左から右へ、アサインメントの表示/非表示、追加カラムの表示/非表示、サムネイルの拡大/縮小を行うためのボタンがあります。 <img src="'+F+'" alt="表示と非表示オプション"></p><h3 id="インポート-エクスポート" tabindex="-1">インポート / エクスポート <a class="header-anchor" href="#インポート-エクスポート" aria-label="Permalink to “インポート / エクスポート”">​</a></h3><p>バッチインポートサムネイル <img src="'+T+'" alt="バッチインポートサムネイル">、最後にインポート <img src="'+p+'" alt="インポートボタン"> またはエクスポート <img src="'+w+'" alt="エクスポートボタン"> データの</p><h3 id="メタデータカラム" tabindex="-1">メタデータカラム <a class="header-anchor" href="#メタデータカラム" aria-label="Permalink to “メタデータカラム”">​</a></h3><p>以下に、カラムの名前があります。「名前」の隣にある(+)をクリックしてください！<a href="../img/getting-started/add_column_custom.png">メタデータカラムの追加</a>をクリックすると、新しいメタデータカラムを作成できます。次に、タスクタイプのカラムの名前があります。</p><h3 id="ビューのカスタマイズ" tabindex="-1">ビューのカスタマイズ <a class="header-anchor" href="#ビューのカスタマイズ" aria-label="Permalink to “ビューのカスタマイズ”">​</a></h3><p>画面の一番右側にあるスクロールバーの隣に、テキストカラムの非表示/表示オプションがあります</p><p><img src="'+I+'" alt="テキストカラムの表示/非表示">。</p><h3 id="ビューの要約" tabindex="-1">ビューの要約 <a class="header-anchor" href="#ビューの要約" aria-label="Permalink to “ビューの要約”">​</a></h3><p>画面の一番下にある最後の部分（4）は、表示されているページの要約です。ページにフィルタを適用すると、要約も更新されます。</p><p>アセットまたはショットの数、見積もり日数、およびすでに費やした日数の合計を確認できます。</p><h2 id="アセットの作成" tabindex="-1">アセットの作成 <a class="header-anchor" href="#アセットの作成" aria-label="Permalink to “アセットの作成”">​</a></h2><h3 id="最初のアセットの作成" tabindex="-1">最初のアセットの作成 <a class="header-anchor" href="#最初のアセットの作成" aria-label="Permalink to “最初のアセットの作成”">​</a></h3><p>制作を作成し、Kitsuインターフェースの概要を理解したので、最初のアセットを作成してみましょう。</p><p>アセットページで、<strong>[アセットを追加]</strong>をクリックします。</p><p><img src="'+N+'" alt="アセットページ初回"></p><p>::: 警告 アセットを作成すると、タスクワークフローが適用され、<strong>すべてのタスクがアセットと同時に作成されます</strong>。 :::</p><p>ポップアップウィンドウが開きます。</p><p><strong>アセットタイプ</strong>を選択するよう求められます（1）。 新しいアセットタイプを追加していない場合、Kitsuは「キャラクター」、「環境」、「エフェクト」、「小道具」などの例を提供します。 まずはキャラクターから始めましょう。</p><p><strong>名前</strong>を入力し (2)、アーティストが何をすべきか理解し、アセットを素早く識別できるように説明を入力します。</p><p>複数のアセットを作成する場合は、<strong>[Confirm and stay]</strong>をクリックします。</p><p><img src="'+B+'" alt="アセットの作成"></p><p>アセットの種類を変更して、アセットを追加し続けることができます。</p><p>::: ヒント 「確認して退出」をクリックするたびに、新しく作成されたアセットが背景に表示されます。 :::</p><p>最後のアセットを追加したら、 「確認」をクリックします。アセットが作成され、ウィンドウが閉じます。</p><p>ヒント 「確認して続行」をクリックしたものの、追加するアセットがないことに気づいた場合は、「閉じる」をクリックすると、ウィンドウがキャンセルされます。 ヒント</p><p><img src="'+O+'" alt="グローバルアセットページ"></p><p>また、アセットワークフローで選択されたタスクも同時に作成されます。</p><p>さらに<strong>アセット</strong>を追加する必要がある場合は、<strong>+ Create assets</strong>（アセットの作成）ボタンをクリックします。</p><p>::: 詳細 CSVスプレッドシートファイルからアセットを作成 アセットのリストがすでにスプレッドシートファイルに用意されている場合もあります。 Kitsuでは、インポートする方法が2つあります。1つ目は、<code>.csv</code>ファイルをインポートし、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、スプレッドシートを<code>.csv</code>ファイルとして保存します。</p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします。 <img src="'+p+'" alt="インポートアイコン"></p><p>ポップアップウィンドウの<strong>「CSVからデータをインポート」</strong>が開きます。<strong>「参照」</strong>をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+G+'" alt="インポートcsvファイル"></p><p>結果を確認するには、<strong>[プレビュー]</strong>ボタンをクリックします。</p><p>データのプレビューで列の名前を確認し、調整することができます。</p><p>注：<strong>[エピソード]</strong>列は、<strong>[テレビ番組]</strong>制作の場合のみ必須です。</p><p><img src="'+g+'" alt="データのコピー＆ペースト"></p><p>すべてが適切であることを確認したら、<strong>[確認]</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータコピーペーストデータ"> :::</p><p>::: 詳細 スプレッドシートファイルのコピー/ペーストによるアセットの作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+n+'" alt="コピーデータのインポート"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ<strong>CSVからのインポート</strong>が開きますので、<strong>CSVデータの貼り付け</strong>タブをクリックします。</p><p><img src="'+$+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+i+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>データのプレビューで列の名前を確認し、調整することができます。</p><p>注意：<strong>エピソード</strong>の列は、<strong>テレビ番組</strong>の制作の場合のみ必須です。</p><p><img src="'+g+'" alt="インポートデータコピーペーストデータ"></p><p>すべて問題なければ、<strong>確認</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされ、設定に従ってタスクが作成されました。</p><p><img src="'+s+'" alt="インポートデータ コピーペーストデータ"> :::</p><h3 id="アセットの詳細を確認する" tabindex="-1">アセットの詳細を確認する <a class="header-anchor" href="#アセットの詳細を確認する" aria-label="Permalink to “アセットの詳細を確認する”">​</a></h3><p>アセットの詳細を確認するには、その名前をクリックします。</p><p><img src="'+y+'" alt="アセットの詳細"></p><p>新しいページが開き、右側にタスク、割り当て、ステータスのニュースフィードの一覧が表示されます。</p><p><img src="'+l+'" alt="アセット詳細ページ"></p><p>各タスクのステータスをクリックすると、コメントパネルが開き、コメントの履歴や異なるバージョンを確認できます。</p><p><img src="'+H+'" alt="アセット詳細ページ"></p><p>また、<strong>キャスティング</strong>にもアクセスできます。</p><p><img src="'+M+'" alt="アセット詳細キャスティング"></p><p>このアセットに関連付けられた<strong>コンセプト</strong>にもアクセスできます。</p><p><img src="'+Q+'" alt="アセット詳細キャスティング"></p><p><strong>スケジュール</strong>は、タスクタイプページのデータを事前に記入していれば利用できます。すでにデータを記入している場合は、ここで直接修正できます。</p><p><img src="'+R+'" alt="アセット詳細キャスティング"></p><p>さまざまなタスクタイプでアップロードされた<strong>プレビューファイル</strong>、</p><p><img src="'+j+'" alt="アセット詳細キャスティング"></p><p>そして、このアセットのタスクでタイムシートが記入された場合の<strong>タイムログ</strong>。</p><p><img src="'+q+'" alt="アセット詳細キャスティング"></p><h2 id="アセットを作成した後にタスクを追加する" tabindex="-1">アセットを作成した後にタスクを追加する <a class="header-anchor" href="#アセットを作成した後にタスクを追加する" aria-label="Permalink to “アセットを作成した後にタスクを追加する”">​</a></h2><p>アセットを作成した後にタスクが欠けていることに気づいた場合でも、追加することができます。</p><p>まず、欠けているタスクタイプがタスクタイプタブの設定ページに追加されていることを確認します。</p><p>次に、アセットページに戻り、<strong>+ タスクを追加</strong>をクリックします</p><h3 id="アセットを更新する" tabindex="-1">アセットを更新する <a class="header-anchor" href="#アセットを更新する" aria-label="Permalink to “アセットを更新する”">​</a></h3><p>アセットはいつでも更新でき、名前やアセットタイプを変更したり、説明文を修正したり、グローバルページに追加したカスタム情報を追加したりすることができます。</p><p>アセットを編集するには、アセットページに移動し、編集したいアセットの上にカーソルを合わせて、<strong>編集</strong>ボタンをクリックします ！<a href="../img/getting-started/edit_button.png">編集ボタン</a> (1) の右側にある 行をクリックします。</p><p><img src="'+e+'" alt="アセットの編集"></p><p>アセットのメインページの説明を拡張するには、最初の語句 (2) をクリックすると、説明の全文を含むポップアップが開きます。</p><p>アセットを削除するには、FAQ : アセットの削除方法を参照してください。</p><p>::: 詳細 CSV インポートによるアセットの更新 CSV インポートを使用すると、データを素早く更新することができます。</p><p>アセットの<strong>タイプ</strong>、<strong>アサイン</strong>、タスクの<strong>ステータス</strong>を更新したり、<strong>コメント</strong>を追加したりすることができます。</p><p><strong>既存のデータを更新する</strong>オプションをオンにする必要があります。すると、更新される行が 青くハイライトされます。</p><p><img src="'+m+'" alt="インポートデータ コピー＆ペーストデータ"></p><p>:::</p><p>::: 詳細 スプレッドシートファイルのコピー＆ペーストによるアセットの更新</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+n+'" alt="インポート コピーデータ"></p><p>次に、Kitsuのアセットページに戻り、<strong>インポート</strong>アイコンをクリックします ！<a href="../img/getting-started/import.png">インポートアイコン</a>。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きます。「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p>！<a href="../img/getting-started/import_pastcsvdata_asset.png">インポートデータコピーペーストタブ</a></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+i+'" alt="データのコピー＆ペースト"></p><p>データをプレビューして、列の名前を確認し、調整することができます。</p><p>注：<strong>[エピソード]</strong> 列は、<strong>[テレビ番組]</strong> 制作の場合のみ必須です。</p><p>オプション「<strong>既存データの更新</strong>」をオンにする必要があります。すると、更新される行が 青くハイライトされます。</p><p><img src="'+m+'" alt="データのインポート データのコピー＆ペースト"></p><p>すべてのアセットをKitsuにインポートし、設定に従ってタスクを作成しました。</p><p><img src="'+s+'" alt="インポートデータ コピーペーストデータ"> :::</p><h2 id="コンセプトの作成" tabindex="-1">コンセプトの作成 <a class="header-anchor" href="#コンセプトの作成" aria-label="Permalink to “コンセプトの作成”">​</a></h2><h3 id="コンセプトのアップロード" tabindex="-1">コンセプトのアップロード <a class="header-anchor" href="#コンセプトのアップロード" aria-label="Permalink to “コンセプトのアップロード”">​</a></h3><p><strong>コンセプト</strong>を作成するには、ナビゲーションメニューから<strong>コンセプト</strong>ページに移動します。</p><p><img src="'+U+'" alt="コンセプトメニュー"></p><p>コンセプトをアップロードするには、「<strong>コンセプトへの新しい参照を追加</strong>」ボタンをクリックします。</p><p>同時に1つまたは複数のコンセプトをアップロードできます。</p><p><img src="'+J+'" alt="コンセプトの空ページ"></p><p>プレビューをアップロードすると、コンセプトページは次のようになります。</p><p><img src="'+X+'" alt="コンセプトの入力ページ"></p><p>コンセプトとやりとりするには2つの方法があります。画像をクリックすると拡大表示されます。 もう1つはステータス部分をクリックして右側の<strong>コメントパネル</strong>を開く方法です。</p><p>コメントパネルでは、コンセプトを既存のアセットにリンクするか、削除するかの2つのオプションがあります。 また、アセットにコメントを追加したり、ステータスを変更することもできます。</p><p><strong>コンセプト</strong>ごとに1つのバージョンを持つことが基本です。承認されていない場合は、同じコンセプトの複数のバージョンを作成しないよう、新しいコンセプトをアップロードする必要があります。</p><p>1つのコンセプトは1つのタスクです。</p><p><img src="'+z+'" alt="コンセプトオプション"></p><h3 id="コンセプトとアセットのリンク" tabindex="-1">コンセプトとアセットのリンク <a class="header-anchor" href="#コンセプトとアセットのリンク" aria-label="Permalink to “コンセプトとアセットのリンク”">​</a></h3><p>コンセプトをアップロードすると、アセットにリンクすることができます。</p><p>リンクはアセットのステータス部分で確認できます。</p><p>コンセプトのステータス部分をクリックすると、右側にコメントパネルが開きます。</p><p><img src="'+W+'" alt="コンセプトコメントパネル"></p><p>コメントパネルの上部には、コンセプトをアセットにリンクするか、コンセプトを削除するかの2つのオプションがあります。</p><p>アセットをリンクするには、[リンク] ボタン <img src="'+Y+'" alt="リンクボタン"> をクリックします。</p><p>Kitsu が、アップロードしたコンセプトにリンク可能なすべての <strong>アセット</strong> を表示します。</p><p>Kitsu は、コメントパネルの上部にリンクされたアセットをリスト表示します。現時点では、リンクはありません。</p><p><img src="'+Z+'" alt="コンセプトリンク"></p><p>アセットをリンクするには、それをクリックします。リンクされたアセットの名前は、コンセプトのプレビューの下の画面の上部に表示されます。</p><p><img src="'+pp+'" alt="コンセプトアセットリンク"></p><p>コンセプトがアセットにリンクされると、アセットの詳細ページで確認できます。</p><p>アセットページに戻り、コンセプトを確認したいアセット名をクリックします。</p><p><img src="'+l+'" alt="アセット詳細ページ"></p><p>デフォルトでは、キャスティングの詳細が画面の2番目の部分に表示されます。 ドロップダウンメニューを使用してコンセプトを選択します。</p><p><img src="'+sp+'" alt="アセット詳細コンセプト"></p><p>コンセプトセクションに入ると、このアセット用に作成されたすべてのコンセプトが表示されます。ステータスごとにフィルタリングすることができます。</p><p><img src="'+tp+'" alt="アセット詳細コンセプトリスト"></p><h2 id="ショットの作成" tabindex="-1">ショットの作成 <a class="header-anchor" href="#ショットの作成" aria-label="Permalink to “ショットの作成”">​</a></h2><h3 id="最初のショットの作成" tabindex="-1">最初のショットの作成 <a class="header-anchor" href="#最初のショットの作成" aria-label="Permalink to “最初のショットの作成”">​</a></h3><p>制作用の<strong>ショット</strong>を作成する時が来ました。</p><p>::: 警告 ショットは、Kitsuのシーケンスにリンクされています。 つまり、シーケンスを作成してから、そのシーケンスにショットを追加する必要があります。 :::</p><p>ショット<strong>ページに移動する必要があります。 ドロップダウンメニューを使用して、</strong>ショット**をクリックします。</p><p><img src="'+rp+'" alt="ドロップダウンメニューショット"></p><p>ショット作成を開始するには、<strong>ショットを追加</strong>ボタンをクリックします。</p><p><img src="'+ap+'" alt="最初のショットの追加"></p><p>::: 警告 ショットを作成すると、設計したタスクワークフローが適用され、すべてのタスクがショットと同時に作成されます。 :::</p><p>ショットの作成用に新しいポップアップが開きます。 これでシーケンスとショットを作成できます。</p><p>最初のシーケンス、例えば「sq01」を入力し、 次に<strong>追加</strong>します。</p><p>シーケンスが作成されたことが確認できます。このシーケンスにショットを追加するには、シーケンスを選択し、ショットを作成します。</p><p>例えば、ショットの列に「sh0010」と入力し、再度<strong>追加</strong>します。 ショットのパディングを定義することもできます。</p><p>::: ヒント ショットをSH0010、SH0020、SH0030のように10個ずつ作成したい場合は、<strong>ショットパディング</strong>を10に設定します :::</p><p><img src="'+op+'" alt="ショットの管理"></p><p>新しいショットがシーケンスごとにリスト化され、リンクされているのが確認できます。 これで最初のシーケンスの最初のショットが作成されました。</p><p>それでは、1つ以上のショットを追加してみましょう！ご覧の通り、ボックスにはすでに名前のコードが含まれていますが、 増分されています。そのため、<strong>追加</strong>をクリックして さらにショットを作成する必要があります。</p><p><img src="'+gp+'" alt="ショットの追加"></p><p>シーケンスを追加するには、左側部分に移動し、新しいシーケンスの名前を入力し、<strong>追加</strong>をクリックします。 2番目のシーケンスが選択され、ショットを追加できるようになります。</p><p>::: ヒント ショットがシーケンス上で誤って配置された場合は、ショットを編集する必要があります ！<a href="../img/getting-started/edit_button.png">編集ボタン</a>をクリックし、 シーケンスを変更します。 ！<a href="../img/getting-started/edit_shot.png">ショットの編集 シーケンスの変更</a></p><p>！<a href="../img/getting-started/change_seq.png">シーケンスの変更</a> :::</p><p>ショットを削除するには、FAQを参照してください。 : ショットの削除方法</p><p>シーケンスを削除するには、FAQを参照してください。 : シーケンスの削除方法</p><h2 id="edlファイルからショットを作成" tabindex="-1">EDLファイルからショットを作成 <a class="header-anchor" href="#edlファイルからショットを作成" aria-label="Permalink to “EDLファイルからショットを作成”">​</a></h2><p>すでに<strong>EDL</strong>ファイルにショットリストが用意されているかもしれません。 Kitsuでは、<strong>EDL</strong>ファイルを直接インポートして、シーケンス、ショット、フレーム数、フレームイン/アウトを作成することができます。</p><p><strong>グローバルショットページ</strong>には、<strong>[インポートEDL]</strong>ボタンがあります。</p><p><img src="'+np+'" alt="インポートEDLボタン"></p><p>ポップアップで、編集時に使用するビデオファイルの命名規則を選択できます。</p><p><img src="'+ip+'" alt="インポートEDLメニュー"></p><p>これは、プロジェクト_シーケンス_ショット.拡張子という名前で編集上のビデオクリップが命名されていることを意味します。</p><p>LGC制作のEDLの例です。</p><p><img src="'+lp+'" alt="EDLの例"></p><p>動画ファイルの名前はLGC_100-000.movです。これは、LGCが制作名、100がシーケンス名、000がショット名であることを意味します。</p><p>命名規則が決まったら、EDLファイルをインポートできます。</p><p>次に、<strong>[Upload EDL]</strong>をクリックします。</p><p>すると、Kitsuがショットを作成します。</p><p><img src="'+ep+'" alt="EDLショット作成"> :::</p><p>::: 詳細 CSVスプレッドシートファイルからショットを作成 ショットのリストがすでにスプレッドシートファイルに用意されているかもしれません。 Kitsuでは、インポートする方法が2つあります。1つ目は、<code>.csv</code>ファイルを直接インポートする方法、2つ目は、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、スプレッドシートを<code>.csv</code>ファイルとして保存します。</p><p>次に、Kitsuのショットページに戻り、<strong>インポート</strong>アイコンをクリックします。 <img src="'+p+'" alt="インポートアイコン"></p><p>「CSVからデータをインポート」というポップアップウィンドウが開きます。「参照」をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+mp+'" alt="CSVファイルのインポート"></p><p>結果を確認するには、「プレビュー」ボタンをクリックします。</p><p>データのプレビューで、列の名前を確認し、調整することができます。</p><p>注：<strong>エピソード</strong>の列は、<strong>テレビ番組</strong>制作の場合のみ必須です。</p><p><img src="'+h+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>すべてが適切であることを確認したら、<strong>確認</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>すべてのショットがKitsuにインポートされ、<strong>設定</strong>に従ってタスクが作成されます。</p><p><img src="'+t+'" alt="インポートデータ コピー＆ペーストデータ"> ::::</p><p>:::: 詳細 スプレッドシートファイルのコピー＆ペーストによるショットの作成 スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+_+'" alt="インポート コピーデータ"></p><p>次に、キットゥのショットページに戻り、<strong>インポート</strong>アイコンをクリックします ！<a href="../img/getting-started/import.png">インポートアイコン</a>。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きます。「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p>！<a href="../img/getting-started/import_pastcsvdata_shot.png">インポートデータコピーペーストタブ</a></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+c+'" alt="データのコピー＆ペースト"></p><p>データのプレビューで列の名前を確認し、調整できます。</p><p>注：<strong>[エピソード]</strong> 列は、<strong>[テレビ番組]</strong> 制作の場合のみ必須です。</p><p><img src="'+h+'" alt="インポートデータのコピー＆ペースト"></p><p>すべてが正しく入力されたら、<strong>Confirm</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>すべてのショットがKitsuにインポートされ、<strong>設定</strong>に従ってタスクが作成されます。</p><p><img src="'+t+'" alt="インポートデータのコピー＆ペースト"> :::</p><h3 id="ショットの詳細を確認する" tabindex="-1">ショットの詳細を確認する <a class="header-anchor" href="#ショットの詳細を確認する" aria-label="Permalink to “ショットの詳細を確認する”">​</a></h3><p>ショットの詳細を確認したい場合は、ショット名をクリックします。</p><p><img src="'+hp+'" alt="ショットの詳細"></p><p>新しいページが開き、右側にタスク、アサイン、ステータス・ニュースフィードの一覧が表示されます。 タブ名をクリックすることで、各ページを移動できます。</p><p><img src="'+_p+'" alt="ショット詳細ページ"></p><p>各タスクのステータスをクリックすると、コメントパネルが開き、コメントの履歴や異なるバージョンを確認できます。</p><p><img src="'+cp+'" alt="ショット詳細ページ"></p><p>また、<strong>キャスティング</strong>にもアクセスできます。</p><p><img src="'+dp+'" alt="アセット詳細キャスティング"></p><p><strong>スケジュール</strong>は、タスクタイプページのデータを事前に記入している場合に利用できます。すでにデータを記入している場合は、ここで直接修正できます。</p><p><img src="'+up+'" alt="アセット詳細キャスティング"></p><p>各種タスクタイプでアップロードされた<strong>プレビューファイル</strong>、</p><p><img src="'+bp+'" alt="アセット詳細キャスティング"></p><p>そして、このアセットのタスクでタイムシートが記入された場合の<strong>タイムログ</strong>。</p><p><img src="'+fp+'" alt="アセット詳細キャスティング"></p><h2 id="ショットを作成した後にタスクを追加する" tabindex="-1">ショットを作成した後にタスクを追加する <a class="header-anchor" href="#ショットを作成した後にタスクを追加する" aria-label="Permalink to “ショットを作成した後にタスクを追加する”">​</a></h2><p>ショットを作成した後にタスクが不足していることに気づいた場合でも、追加することができます。</p><p>まず、不足しているタスクタイプがタスクタイプタブの設定ページに追加されていることを確認します。</p><p>次にショットページに戻り、+タスクを追加をクリックします。</p><h3 id="ショットを更新する" tabindex="-1">ショットを更新する <a class="header-anchor" href="#ショットを更新する" aria-label="Permalink to “ショットを更新する”">​</a></h3><p>ショットはいつでも更新でき、名前や順序を変更したり、説明を修正したり、グローバルページに追加したカスタム情報を追加したりすることができます。</p><p>ショットを編集するには、ショットページに移動し、変更したいショットの上にカーソルを移動させて、行の右側にある<strong>[編集]</strong>ボタンをクリックします ！<a href="../img/getting-started/edit_button.png">編集ボタン</a> (1)。</p><p><img src="'+e+'" alt="アセットの編集"></p><p>メインショットページの説明を拡張するには、最初の文字 (2) をクリックすると、説明の全文を含むポップアップが開きます。</p><p>::: 詳細 ショット情報のCSVインポートによる更新 CSVインポート<strong>を使用して、</strong>NBフレーム<strong>、</strong>フレームIN<strong>、</strong>フレームOUT<strong>、または任意のカスタム</strong>メタデータ列**としてデータを更新することができます。</p><p>アサインメント<strong>、タスクの</strong>ステータス<strong>を更新し、</strong>コメント**を追加することができます。</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+_+'" alt="インポートコピーデータ"></p><p>次に、Kitsuのショットページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ<strong>インポートデータからCSV</strong>が開きます。<strong>CSVデータを貼り付け</strong>タブをクリックします。</p><p><img src="'+Kp+'" alt="インポートデータのコピー＆ペーストタブ"></p><p>以前に選択したデータをペーストし、<strong>[プレビュー]</strong>ボタンで結果を確認できます。</p><p><img src="'+c+'" alt="インポートデータのコピー＆ペーストデータ"></p><p>オプション：既存データの更新** をオンにする必要があります。 更新されたショットは青くなります。</p><p>注：<strong>エピソード</strong>の列は、<strong>テレビ番組</strong>制作の場合のみ必須です。</p><p><img src="'+kp+'" alt="インポートデータのコピー＆ペースト"></p><p>すべてが正しく入力されたら、<strong>Confirm</strong> ボタンをクリックしてデータをKitsuにインポートします。</p><p>すべてのショットがKitsuにインポートされ、<strong>Settings</strong>に従ってタスクが作成されます。</p><p><img src="'+t+'" alt="Import data copy paste data"> :::</p><h2 id="ショットにフレーム数とフレーム範囲を追加する" tabindex="-1">ショットにフレーム数とフレーム範囲を追加する <a class="header-anchor" href="#ショットにフレーム数とフレーム範囲を追加する" aria-label="Permalink to “ショットにフレーム数とフレーム範囲を追加する”">​</a></h2><p>この段階では、アニマティックが完了しているはずです。つまり、 各ショットの長さ（<strong>フレーム数</strong>、<strong>フレーム範囲イン</strong>、<strong>フレーム範囲アウト</strong>）が分かっているはずです。 この情報をスプレッドシートに追加できます。この方法であれば、 すべてのフレームが計算され、抜けや過剰計算がないことを確認できます。</p><p>::: 警告 ショットとシーケンスを手動で作成した場合、 「フレーム」列は非表示になります。「フレーム」列を表示するには、少なくとも1つのショットを編集してフレーム数を入力する必要があります。 ショットをCSV/スプレッドシートで作成し、フレーム数をインポートした場合は、列が表示されます。 :::</p><p>ショットを編集してフレーム範囲の情報を入力する必要があります。 編集ボタンをクリックしてください！<a href="../img/getting-started/edit_button.png">編集ボタン</a> ショット行の右側にある</p><p>！<a href="../img/getting-started/edit_shot.png">ショット編集 シーケンス変更</a></p><p>新しいウィンドウでショットの<strong>In</strong>と<strong>Out</strong>を入力できます。その後、<strong>確認</strong>ボタンをクリックして保存します。</p><p><img src="'+xp+'" alt="ショット編集ページ"></p><p>これで、ショットページの全体スプレッドシートにフレーム範囲が表示されます。</p><p><img src="'+Pp+'" alt="ショット編集ページ"></p><p><strong>フレーム</strong>、<strong>イン</strong>、<strong>アウト</strong>の列のロックを解除したので、 グローバルショットページから直接入力することができます。</p><p>入力したいケースをクリックしてデータを追加します。</p><p>::: ヒント <strong>フレームイン</strong>と<strong>フレームアウト</strong>を入力すると、Kitsが自動的に<strong>フレーム数</strong>を計算します。 :::</p><p><img src="'+Cp+'" alt="ショット編集ページ"></p><p><strong>CSVインポート</strong>を使用して、フレーム範囲をすばやく更新することもできます。 CSVインポートでショット情報を更新</p><p>ショット値の履歴にもアクセスできます。</p><p><img src="'+Sp+'" alt="ショットのフレームレートの詳細"></p><p><img src="'+Vp+'" alt="ショット値の履歴"></p><h2 id="カスタムメタデータカラムの作成" tabindex="-1">カスタムメタデータカラムの作成 <a class="header-anchor" href="#カスタムメタデータカラムの作成" aria-label="Permalink to “カスタムメタデータカラムの作成”">​</a></h2><p>一般的なスプレッドシートページにさらに情報を追加するには、カスタム<strong>メタデータカラム</strong>を作成する必要があります。</p><p>ページに追加する追加情報として、<strong>難易度レベル</strong>、<strong>天候</strong>、<strong>タグ</strong>などがあります。 カスタムメタデータカラムには、すべてのテキスト（または数値）情報を保存できます。</p><p>名前カラムの近くにある<strong>+</strong>をクリックします。</p><p><img src="'+Dp+'" alt="メタデータカラム"></p><p>タイプ**オプションでは、情報をどのように保存するかを選択できます。</p><ul><li>自由入力の<strong>テキスト</strong>、</li><li><strong>数値</strong>、</li><li><strong>チェックボックス</strong>、</li><li><strong>選択肢リスト</strong>、</li><li><strong>タグリスト</strong>、</li><li><strong>チェックリスト</strong>。</li></ul><p><img src="'+Ep+'" alt="メタデータ カラム詳細"></p><p>::: 警告 <strong>テキスト</strong>、<strong>数値</strong>、および<strong>チェックボックス</strong>では、各エンティティに対して異なる情報を追加することができます。 最初に計画する必要はありません。</p><p><strong>値のリスト</strong>、<strong>タグのリスト</strong>、および<strong>チェックリスト</strong>では、各エンティティに対して同じ選択肢が提供されます。さらに、これは現在入力する必要があります。</p><p><img src="'+Lp+'" alt="メタデータカラムリスト"></p><p>利用可能な値<strong>の下にリスト要素を入力し、</strong>値を追加**をクリックして確認します。 :::</p><p>メタデータカラム<strong>を1つまたは複数の</strong>部門**にリンクすることもできます。</p><p>::: ヒント メタデータカラムを部門にリンクします。アーティスト/スーパーバイザーは、自分のToDoページおよび部門フィルタリングビューでこれを見ることができます。</p><p>メタデータ列を1つまたは複数の部門にリンクすることができます。リストから部門をクリックし、<strong>追加</strong>をクリックして有効にします。</p><p>ここでは、VFX列が2つの部門にリンクされています。</p><p><img src="'+vp+'" alt="部門メタデータ列のフィルタリングビュー"></p><p>:::</p><p>::: 詳細 メタカラムの編集 アセットまたはショットのグローバルページで、メタデータカラムの右端にある矢印をクリックし、<strong>[編集]</strong>をクリックします。</p><p><img src="'+Ap+'" alt="メタデータカラムの編集"> :::</p><p>この情報は、グローバルスプレッドシートページで直接入力できます。 ケースは編集可能です。</p><p><img src="'+Fp+'" alt="メタデータ列の詳細"></p><p>::: ヒント 左側の複数のエンティティを選択し、メタデータ列を一括で変更することができます。 :::</p><p>::: 詳細 手動で編集 編集ボタン <img src="'+Tp+'" alt="編集ボタン"> を使用して情報を変更することもできます。</p><p>編集ポップアップに新しい行が表示されます。リストから情報を選択するか、 あるいは、選択内容に応じて、自由形式のテキストや数値を入力したり、チェックボックスにチェックを入れたり、チェックリストを使用したりすることができます。</p><p>編集が完了したら、必ず「確認」ボタンをクリックしてください。</p><p><img src="'+wp+'" alt="メタデータ列の詳細"> :::</p><p>メタデータ列を編集または削除するには、スプレッドシートの一般ページに移動します。 メタデータ列の名前の近くにある矢印 <img src="'+Ip+'" alt="Metadata Column detail"> をクリックします。</p><p>::: ヒント この新しい列を使用して、グローバルページを<strong>ソート</strong>することができます。列名の右にある矢印をクリックして、メニューを開きます。次に、<strong>ソート</strong>をクリックします。</p><p>メタデータ列を左側に<strong>固定</strong>することもできます。 :::</p><h2 id="シーケンスの作成" tabindex="-1">シーケンスの作成 <a class="header-anchor" href="#シーケンスの作成" aria-label="Permalink to “シーケンスの作成”">​</a></h2><p>Kitsuでは、<strong>シーケンス</strong>レベルでタスクを追跡することもできます。 これは、 ストーリーやカラーボード、カラーグレーディングなど、マクロタスクを追跡する際に特に便利です。</p><p>ナビゲーションメニューを使用して、<strong>シーケンス</strong>ページに移動します。</p><p><img src="'+Np+'" alt="ナビゲーションシーケンス"></p><p>::: 警告 この新しいページは、アセットおよびショットのグローバルページと同様に動作します。</p><p>このページを使用するには、まず<strong>グローバルライブラリ</strong>に<strong>シーケンス</strong>属性を持つ専用のタスクタイプを作成する必要があります。</p><p>新しい <strong>タスクタイプ</strong> を作成するには、<strong>新しいタスクタイプの作成</strong> セクションを参照してください。</p><p><a href="./../configure-kitsu/#タスクの種類">新しいタスクタイプの作成</a></p><p>グローバルライブラリで<strong>タスクタイプ</strong>を作成したら、それを** プロダクションライブラリ**（設定ページ）に追加します。 :::</p><p>タスクタイプが設定ページで準備できたら、シーケンス（アセットまたはショットと同じ）を作成する必要があります。</p><p>この新しいページは、アセットやショットのグローバルページと同様に動作します。<strong>+ 新規シーケンス</strong> ボタンで編集を追加できます。</p><p>タスクの割り当て、レビュー、ステータスの変更などを行うことができます。</p><p>メタデータ列を追加したり、説明を記入したりすることができます。</p><p>::: ヒント シーケンスは、ここ（+新規シーケンスボタン）から直接作成することも、グローバルショットページからショットにリンクされたシーケンスを作成することもできます。 :::</p><p>このページでは、アセットやショットと同様に、シーケンスのエンティティを<strong>名前変更</strong>したり、<strong>削除</strong>したりすることができます。</p><p>シーケンス名をクリックすると、そのシーケンスの詳細ページが表示されます。</p><p><img src="'+Bp+'" alt="シーケンスの詳細ページ"></p><p>詳細ページでは、シーケンスのキャストにアクセスできます。 シーケンス全体で使用されているすべてのアセットを確認できます。</p><p>また、シーケンスのタスクのスケジュール、プレビューファイル、アクティビティ、タイムログにもアクセスできます。</p><h2 id="編集の作成" tabindex="-1">編集の作成 <a class="header-anchor" href="#編集の作成" aria-label="Permalink to “編集の作成”">​</a></h2><p>Kitsuでは、<strong>編集</strong>レベルでタスクを追跡できます。</p><p>特に、 複数の編集を複数の検証ステップで追跡する必要がある場合に便利です。 例えば、映画全体、複数の予告編、ファースト・エディット、ファイン・エディット、ミックスなどを追跡できます。</p><p>::: 警告 デフォルトでは、<strong>Edit</strong>ページは、<strong>制作ライブラリ</strong>（設定ページ）にそれ用のタスクタイプが作成されるまで表示されません :::</p><p>このページを使用するには、まず<strong>グローバルライブラリ</strong>に<strong>Edit</strong>属性を持つ専用のタスクタイプを作成する必要があります。</p><p>新しい <strong>タスクタイプ</strong> を作成するには、<strong>新しいタスクタイプの作成</strong> セクションを参照してください。</p><p><a href="./../configure-kitsu/#タスクの種類">新しいタスクタイプの作成</a></p><p>グローバルライブラリで<strong>タスクタイプ</strong>を作成したら、<strong>プロダクションライブラリ</strong>に追加します。 すると、ナビゲーションのドロップダウンメニューに<strong>編集</strong>が表示されます。</p><p><img src="'+Op+'" alt="ナビゲーションの編集"></p><p>この新しいページは、アセットおよびショットのグローバルページと同様に動作します。<strong>+ 新規編集</strong> ボタンで編集を追加できます。</p><p>タスクの割り当て、レビュー、ステータスの変更などを行うことができます。</p><p>メタデータ列を追加したり、説明を記入したりすることができます。</p><p>::: ヒント 配信内容によっては、<strong>[編集]</strong> ごとに解像度を変更することもできます。 :::</p><p>::: 警告 詳細ページは他のエンティティとは異なります。</p><p><strong>編集</strong>は特定のロングビデオに焦点を当てているため、詳細ページはコメント詳細ページにより似たものとなります。 :::</p><p>このページでは、アセットおよびショットエンティティの編集エンティティを<strong>名前変更</strong>および<strong>削除</strong>することができます。</p><h2 id="ブレイクダウンリストの作成" tabindex="-1">ブレイクダウンリストの作成 <a class="header-anchor" href="#ブレイクダウンリストの作成" aria-label="Permalink to “ブレイクダウンリストの作成”">​</a></h2><p>ブレイクダウンを記入すると、ショットの組み立てに役立ちます。 ブレイクダウンには、ショットを作成するために追加する必要のあるアセットのすべての詳細が記載されています。 これにより、何も見落とすことがなくなります。</p><p>ドロップダウンメニューで <strong>[BREAKDOWN]</strong> を選択します。</p><p><img src="'+Gp+'" alt="drop down Menu breakdown"></p><p>ブレークダウンページの左側には、エピソード/シークエンス/ショットメニュー（1）があります。作成したものの中から選択できます。これらは画面の右側に表示され、 作成したすべてのアセットは、この制作（メインパックおよびエピソード）で利用できます（3）。さらに、 中央セクションには、ショットの選択肢が表示されます（2）。</p><p><img src="'+$p+'" alt="ブレークダウンページ"></p><p>では、次にキャストしたいショットを選択します。</p><p>サムネイルがまだない場合はアセットをテキストで表示したり、 サムネイルのサイズを拡大することができます。</p><p><img src="'+yp+'" alt="ブレイクダウンページのテキスト表示"></p><p>また、ブレイクダウン中にリストにアセットを追加する必要があることに気づくかもしれません。</p><p>ブレークダウンページから直接、新しいアセットを作成することができます。「利用可能なすべてのアセット」の右側にある「+」をクリックします。</p><p><img src="'+Hp+'" alt="ブレークダウンページでアセットを作成"></p><p>また、複数のショットを一度に選択することもできます。最初のショットをクリックし、<strong>シフト</strong>キーを押したまま、選択する最後のショットをクリックします。</p><p><img src="'+Mp+'" alt="ページのグローバル一括選択"></p><p>次に、割り当てたいアセットをクリックします。 キャラクター、背景など、右側の部分 (3) から選択します。 複数のショットを選択した場合、選択した内容は多数のショットに適用されます。</p><p>アセットが配置されたショットをコピーし、このアセット選択を別のショットに貼り付けます。</p><p>アセットの上にカーソルを移動させると、<strong>+1</strong> または <strong>+10</strong> と表示されます。これは、 そのアセットを追加した回数を表しており、必要なだけクリックできます。</p><p><img src="'+Qp+'" alt="ブレークダウンでアセットを追加"></p><p>シーケンスやショットを指定せずに、すべてのアセットをテレビ番組のエピソードにリンクすることもできます。</p><p><img src="'+Rp+'" alt="Breakdown episode asset"></p><p>この方法では、ストーリーボード/アニマティックの段階の前に、すべてのアセットを1つまたは複数のエピソードにリンクすることができます。</p><p>画面中央にアセットが表示されているのが確認できます（2）。 アセット名の隣には、追加された回数が表示されています。この 例では、キャラクターアセット「Llama」を2回追加しています。</p><p>誤ってアセットを2回追加してしまった場合は、画面中央部分でこのショットのアセットを選択する必要があります（2）。そこから、<strong>-1</strong>をクリックします。 このショットの作業が完了したら、他のショットの作業に進みます。 選択した内容は自動的に保存されます。</p><p><img src="'+jp+'" alt="アセットの削除"></p><p>ストーリーボードの作成中に新しいアセットが作成された場合は、アセットページに戻り （ドロップダウンメニューを使用）、必要なアセットを作成します。以前に作成したタスクは、これらの新しいアセットに即座に適用されます。 ただし、割り当てを行う必要があり、その後、 ブレークダウンを継続できます。</p><p>これで、<strong>Breakdown</strong>ページは以下のようになります。</p><p><img src="'+r+'" alt="breakdown add asset bulk"></p><p>アセットを組み立てて個々のパーツを追跡する必要がある場合は、アセットのブレークダウンリストを作成することもできます。</p><p>画面左上にある<strong>FOR</strong>の下のドロップダウンメニューで<strong>asset</strong>を選択します。</p><p><img src="'+qp+'" alt="アセットの分類メニュー"></p><p>2番目のドロップダウンメニューにアクセスして、アセットの種類を選択できます。 <strong>キャラクター</strong>、<strong>環境</strong>、<strong>小道具</strong>、<strong>FX</strong>、...</p><p><img src="'+Up+'" alt="アセットタイプの分類"></p><p>ショットの分類と同様の方法で、アセットの分類ページを完成させることができます。 まず、左側の部分で1つまたは複数のアセットを選択し、次に右側の部分の要素を追加します。</p><p>::: 詳細 CSVファイルからブレイクダウンリストを作成する</p><p>すでにスプレッドシートファイルでブレイクダウンリストが準備できているかもしれません。Kitsuでは、それをインポートする方法が2つあります。1つ目は、.csvファイルを直接インポートする方法、2つ目は、データを直接Kitsuにコピー＆ペーストする方法です。</p><p>まず、Kitsuの推奨に従って、スプレッドシートを「.csv」ファイルとして保存します。</p><p>インポート]ボタンをクリックします！[インポート]ボタン（../img/getting-started/import.png）</p><p>「CSVからデータをインポート」というポップアップウィンドウが開きます。「参照」をクリックして、<code>.csv</code>ファイルを選択します。</p><p><img src="'+d+'" alt="インポートされたCSVファイルのブレークダウン"></p><p>結果を確認するには、「プレビュー」ボタンをクリックします。</p><p>データのプレビューで列名を確認し、必要に応じて調整します。</p><p>注：<strong>[エピソード]</strong>列は、<strong>[テレビ番組]</strong>制作の場合のみ必須です。</p><p><img src="'+a+'" alt="ブレークダウンインポートプレビュー"></p><p>すべてが適切であることを確認したら、<strong>[確認]</strong>ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、ブレークダウンがKitsuにインポートされました。</p><p><img src="'+r+'" alt="ブレークダウンインポートプレビュー"> :::</p><p>::: 詳細 スプレッドシートファイルをコピー＆ペーストしてブレークダウンリストを作成</p><p>スプレッドシートを開き、データを選択してコピーします。</p><p><img src="'+Jp+'" alt="インポートコピーデータ"></p><p>次に、Kitsuのブレークダウンページに戻り、<strong>インポート</strong>アイコンをクリックします <img src="'+p+'" alt="インポートアイコン">。</p><p>ポップアップウィンドウ「<strong>CSVからデータをインポート</strong>」が開きますので、「<strong>CSVデータを貼り付け</strong>」タブをクリックします。</p><p><img src="'+d+'" alt="インポートデータコピーペーストタブ"></p><p>以前に選択したデータを貼り付け、<strong>[プレビュー]</strong> ボタンで結果を確認できます。</p><p><img src="'+a+'" alt="データのコピー＆ペースト"></p><p>データのプレビューで列の名前を確認し、調整できます。</p><p>注：<strong>[エピソード]</strong> 列は、<strong>[テレビ番組]</strong> 制作の場合のみ必須です。</p><p><img src="'+a+'" alt="インポートデータのコピー＆ペースト"></p><p>すべてが適切であることを確認したら、<strong>Confirm</strong>（確認）ボタンをクリックしてデータをKitsuにインポートします。</p><p>これで、すべてのアセットがKitsuにインポートされました。</p><p><img src="'+r+'" alt="インポートデータのコピー＆ペースト"> :::</p><h2 id="アセットの状態の紹介-使用可能" tabindex="-1">アセットの状態の紹介：使用可能 <a class="header-anchor" href="#アセットの状態の紹介-使用可能" aria-label="Permalink to “アセットの状態の紹介：使用可能”">​</a></h2><p>ほとんどの場合、ショットタスクでアセットを使用する際に、アセットのタスクが承認されるのを待つ必要はありません。</p><p>たとえば、アセットが<strong>コンセプト</strong>段階で承認された場合、<strong>ストーリーボード</strong>段階で使用することができます。 次に、<strong>モデリング</strong>段階で承認された場合、<strong>レイアウト</strong>段階で使用することができます。</p><p>まさにアセットの状態<strong>「準備完了」</strong>がやっていることです。この状態は、アセットのタスクの状態を知らせ、ショットのタスクに対する使用可能性を比較します。</p><p>ブレークダウンを記入したので、どのショットにどのアセットが使用されているかが正確にわかります。</p><p>まず、タスクのステータスと関連するアセットの状態を定義する必要があります。セルをクリックして<strong>準備完了</strong>を変更することができます。ショットタスクのドロップダウンメニューが表示されます。</p><p><img src="'+Xp+'" alt="アセットステータス"></p><p>::: ヒント <strong>自動化</strong>を使用して、重労働を軽減することができます。</p><p>「準備完了」トリガーで自動化を設定できます。 :::</p><p>アセットの状態をいくつか「準備完了」に変更したので、ショットページで結果を確認できます。</p><p>いくつかの白いボックスが「緑色」になっていることに気づくでしょう。このショットで使用されるすべてのアセットが、この特定のタスクの準備が完了していることを示しています。</p><p><img src="'+zp+'" alt="アセットステータス"></p><p>白いボックスが表示されている場合、Kitsuは、このタスクに準備ができているアセットの数を示します。</p><p><img src="'+Wp+'" alt="アセットステータス"></p><p>::: ヒント ボックスが表示されていない場合、このショットにはアセットが割り当てられていません。 :::</p><p>ショット名をクリックすると、詳細ページに移動します。 すると、そのショットで使用されているすべてのアセットとそのステータスが表示されます。</p><p><img src="'+Yp+'" alt="アセットステータス"></p><p>特定のタスクでショットを開始できるかどうかを判断する最も簡単な方法です。</p>',471)])])}const is=u(Zp,[["render",ps]]);export{ns as __pageData,is as default};
